// Solution
function validateCommitHash(s) {
	// Check if the string starts with '0'
	if (s.startsWith('0')) {
		// Check if the string has a length of 40
		if (s.length === 40) {
			// Check if the last 6 characters are hexadecimal digits
			for (let i = 38; i < 40; i++) {
				if (!((s[i] >= '0' && s[i] <= '9') || (s[i] >= 'A' && s[i] <= 'F'))) {
					return false;
				}
			}
			return true;
		}
	}
	return false;
}

