class Solution:
    def validateCommitHash(self, s: str) -> bool:
        # Check if the string starts with '0'
        if s.startswith('0'):
            # Check if the string has a length of 40
            if len(s) == 40:
                # Check if the last 6 characters are hexadecimal digits
                for i in range(38, 40):
                    if not ((s[i] >= '0' and s[i] <= '9') or (s[i] >= 'A' and s[i] <= 'F')):
                        return False
                return True
        return False
